#include <iostream>
#include <algorithm>

using namespace std;

class Solution {
public:
bool solve(int arr[], int n) {
	for(int i = 0; i < n / 2; i++) {
		swap(arr[i], arr[n - i - 1]);
	}
	return true;
}};

